#include<bits/stdc++.h>
using namespace std;
long long n,a[100005],f[100005];
string s;
int main() {
	cin>>n>>s;
	s=" "+s;
	for(int i=1;i<=n;i++){
		cin>>a[i];
		if(i%2!=0)a[i]=-a[i];
	}
	for(int i=n;i>=1;i--)
	f[i]=f[i+1]+a[i];
	for(int i=1;i<=n;i++)
	cout<<(char)(((s[i]-'a'+f[i])%26+26)%26+'a');
}
